// Filtrar propiedades nuevas que califican para alerta
const data = $input.first().json.data || []
const run  = $input.first().json.run  || {}

const qualifying = data.filter(a => {
  if (!a.price_usd) return false
  if (a.price_usd > 90000) return false
  if (a.location_department && !a.location_department.includes('LIMA') && !a.location_department.includes('CALLAO')) return false
  return true
}).sort((a, b) => (a.price_usd || 0) - (b.price_usd || 0))

const stats = {
  total:       data.length,
  qualifying:  qualifying.length,
  new_records: run.new_records || 0,
  pages:       run.pages_scraped || 0,
  duration_ms: run.duration_ms || 0
}

return [{ json: { qualifying, stats, run_id: $input.first().json.run_id } }]

// Construir digest cuando hay muchas propiedades
const { qualifying, stats } = $input.first().json

const tierCount = { super_ganga: 0, muy_bueno: 0, bueno: 0, aceptable: 0 }
qualifying.forEach(a => { if (a.price_usd_tier) tierCount[a.price_usd_tier]++ })

const date = new Date().toLocaleDateString('es-PE', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'America/Lima' })

let msg = `📊 *RESUMEN DIARIO REMAJU*\n`
msg += `━━━━━━━━━━━━━━━━━━━━━━\n`
msg += `🗓  ${date}\n\n`
msg += `*${qualifying.length} nuevas propiedades < $90k USD*\n\n`
if (tierCount.super_ganga) msg += `🔴 Super Ganga (< $40k): ${tierCount.super_ganga}\n`
if (tierCount.muy_bueno)   msg += `🟠 Muy Bueno  ($40-60k): ${tierCount.muy_bueno}\n`
if (tierCount.bueno)       msg += `🟡 Bueno      ($60-75k): ${tierCount.bueno}\n`
if (tierCount.aceptable)   msg += `🟢 Aceptable  ($75-90k): ${tierCount.aceptable}\n`

// Top 3
const top3 = qualifying.slice(0, 3)
msg += `\n*🏆 Top 3 más económicas:*\n`
top3.forEach((a, i) => {
  const usd  = `$${Math.round(a.price_usd).toLocaleString('es-PE')}`
  const dist = a.location_district || a.location_department || 'Lima'
  const tipo = (a.property_type || 'inmueble').charAt(0).toUpperCase() + (a.property_type || 'inmueble').slice(1)
  msg += `${i+1}. ${usd} — ${tipo} en ${dist}\n`
})

if (stats.pages) msg += `\n_Páginas revisadas: ${stats.pages} | ${Math.round(stats.duration_ms/60000)} min_`

return [{ json: { text: msg, parse_mode: 'Markdown' } }]

// Construir mensajes individuales por propiedad
const { qualifying } = $input.first().json

const TIER_EMOJI  = { super_ganga:'🔴', muy_bueno:'🟠', bueno:'🟡', aceptable:'🟢' }
const TIER_LABEL  = { super_ganga:'SUPER GANGA', muy_bueno:'MUY BUENO', bueno:'BUENO', aceptable:'ACEPTABLE' }
const TYPE_EMOJI  = { casa:'🏠', departamento:'🏢', terreno:'🌿', local:'🏪', otro:'🏗️' }

return qualifying.map(a => {
  const tier  = a.price_usd_tier || 'aceptable'
  const emoji = TIER_EMOJI[tier] || '🟢'
  const label = TIER_LABEL[tier] || ''
  const typeE = TYPE_EMOJI[a.property_type] || '🏗️'

  const usd   = `$${Math.round(a.price_usd).toLocaleString('es-PE')}`
  const pen   = a.currency_original === 'PEN' ? `S/ ${Math.round(a.price_original).toLocaleString('es-PE')}  ≈  ` : ''
  const phase = a.auction_phase ? a.auction_phase.includes('SEGUNDA') ? ' · 2da Conv ↓15%' : a.auction_phase.includes('TERCERA') ? ' · 3ra Conv ↓30%' : '' : ''

  let text = `${emoji} *REMATE LIMA — ${label}*\n`
  text += `━━━━━━━━━━━━━━━━━━━━━━\n`
  text += `💰  ${pen}*${usd}*\n`
  if (a.exchange_rate) text += `💱  TC: S/ ${parseFloat(a.exchange_rate).toFixed(2)}/USD\n`
  if (a.location_district) text += `📍  ${a.location_district}, Lima\n`
  text += `${typeE}  ${(a.property_type||'inmueble').charAt(0).toUpperCase()}${(a.property_type||'inmueble').slice(1)}${phase}\n`
  if (a.area_m2) {
    const m2 = Math.round(a.price_usd / a.area_m2)
    text += `📐  ${a.area_m2} m²  ·  $${m2}/m²\n`
  }
  if (a.expediente) text += `📋  \`${a.expediente}\`\n`
  if (a.juzgado)    text += `⚖️  ${a.juzgado}\n`
  if (a.auction_date) {
    const days = Math.ceil((new Date(a.auction_date) - new Date()) / 86400000)
    const urgency = days <= 7 ? ` ⚡ ¡${days} días!` : ` (${days} días)`
    text += `📅  Remate: ${a.auction_date}${urgency}\n`
  }
  if (a.detail_url) text += `\n[🔗 Ver en REMAJU](${a.detail_url})\n`

  const tags = [`#${tier}`, '#Lima', a.property_type ? `#${a.property_type}` : '', a.location_district ? `#${a.location_district.replace(/\s+/g,'')}` : ''].filter(Boolean)
  text += `\n${tags.join(' ')}`

  return { json: { text, parse_mode: 'Markdown', auction_id: a.id } }
})
